// استخراج رسالة المستخدم وإعداد طلب البحث
const message = $input.first().json.chatInput || $input.first().json.message || '';
const sessionId = $input.first().json.sessionId || 'default';

return [{
  json: {
    query: message,
    sessionId: sessionId,
    timestamp: new Date().toISOString()
  }
}];

// تجهيز السياق من نتائج ChromaDB
const query = $('📝 استخراج السؤال').first().json.query;
const chromaResult = $input.first().json;

let context = '';
let sources = [];

try {
  if (chromaResult && !chromaResult.error && chromaResult.documents) {
    const documents = chromaResult.documents[0] || [];
    const metadatas = chromaResult.metadatas[0] || [];
    const distances = chromaResult.distances[0] || [];
    if (documents.length > 0) {
      documents.forEach(function(doc, i) {
        if ((distances[i] || 999) < 1.5) {
          const meta = metadatas[i] || {};
          const source = meta.source_name || meta.source || 'مصدر قانوني';
          sources.push(source);
          context += '[' + source + ']:\n' + doc + '\n\n---\n\n';
        }
      });
    }
  }
} catch(e) {
  context = '';
}

const systemPrompt = 'أنت مساعد قانوني متخصص في الأنظمة والتشريعات السعودية.\n'
  + 'أجب على الأسئلة بدقة واحترافية باللغة العربية.\n'
  + 'استند إلى النصوص القانونية المقدمة إذا كانت متاحة.\n'
  + 'إذا لم تجد إجابة في النصوص، وضّح ذلك وقدّم معلومات عامة مفيدة.\n\n'
  + (context ? ('السياق القانوني المتاح:\n' + context) : 'لا توجد نصوص قانونية محددة متاحة لهذا السؤال.');

return [{
  json: {
    query: query,
    systemPrompt: systemPrompt,
    hasContext: context.length > 0,
    sources: sources.filter(function(v, i, a) { return a.indexOf(v) === i; })
  }
}];

// تنسيق الإجابة النهائية
const rawInput = $input.first().json;
// n8n HTTP Request node يضع الاستجابة في .data أو مباشرة في json
const ollamaResponse = rawInput?.data || rawInput;
const contextData = $('📚 تجهيز السياق القانوني').first().json;

let answer = '';
try {
  // /api/chat يرجع: { message: { content: "..." } }
  // /api/generate يرجع: { response: "..." }
  answer = ollamaResponse?.message?.content 
        || ollamaResponse?.response 
        || '';
} catch(e) {
  answer = '';
}

if (!answer || answer.trim() === '') {
  answer = 'عذراً، لم أتمكن من توليد إجابة. يرجى المحاولة مرة أخرى.';
}

// إضافة المصادر إذا وُجدت
if (contextData && contextData.hasContext && contextData.sources && contextData.sources.length > 0) {
  answer += '\n\n---\n📚 **المصادر:** ' + contextData.sources.join('، ');
}

return [{
  json: {
    output: answer
  }
}];
